import org.jfree.chart.AbstractDrawable;
import java.awt.geom.Rectangle2D;
import java.awt.Shape;
import java.awt.BasicStroke;
import org.jfree.ui.TextAnchor;
import java.awt.Color;
import java.awt.Font;
import org.jfree.chart.JFreeChart;
import java.awt.Paint;
import java.awt.Stroke;

public class ValueMarker extends AbstractDrawable implements Cloneable, Serializable {
     private double value = 0.0;
    public ValueMarker(double value, Paint paint, Stroke stroke, Paint outlinePaint, Stroke outlineStroke, float alpha){
        setPaint(paint);
        setStroke(stroke);
        setOutlinePaint(outlinePaint);
        setOutlineStroke(outlineStroke);
        setAlpha(alpha);
        if(value > 1 || value < 0 ){
            throw new IllegalArgumentException("The 'value' must be between 0 and 1.");
        } else {
            this.value=value;
        }

        if (paint == null || stroke == null || outlinePaint == null || outlineStroke == null){
            throw new IllegalArgumentException ("Parameters cannot be null");
        }  

      if (alpha<0 || alpha>1f){
            throw new IllegalArgumentException ("The 'alpha' must be in range of [0..1]");
        }      
    }

    public double getValue(){
        return value;
    }

}

